    def test_config_flag_overrides_default(temp_files):
        """--config flag should override default discovery"""
        home = Path(temp_files.tempdir) / "home"
        home.mkdir()
        config_dir = home / ".config" / "i3"
        config_dir.mkdir(parents=True)

        # Create default config
        default_config = config_dir / "config"
        default_config.write_text("""
    font pango:Default 10
    client.focused #ffffff #ffffff #000000
    bar {
      colors {
        separator #ffffff
      }
    }
    """)

        # Create custom config
        custom_config = temp_files.create("custom", """
    font pango:Custom 12
    client.focused #ffffff #ffffff #000000
    bar {
      colors {
        separator #ffffff
      }
    }
    """)

